import{_ as t,o as r,c as a,a2 as i}from"./chunks/framework.c3r8iWL8.js";const p=JSON.parse('{"title":"SOP-005: Pull Request Review & Merge","description":"Reference template for AI-native enterprise delivery on AWS","frontmatter":{},"headers":[],"relativePath":"sops/SOP-005-pr-review.md","filePath":"sops/SOP-005-pr-review.md","lastUpdated":1782929962000}'),d={name:"sops/SOP-005-pr-review.md"};function s(o,e,l,n,h,c){return r(),a("div",null,[...e[0]||(e[0]=[i('<h1 id="sop-005-pull-request-review-merge" tabindex="-1">SOP-005: Pull Request Review &amp; Merge <a class="header-anchor" href="#sop-005-pull-request-review-merge" aria-label="Permalink to &quot;SOP-005: Pull Request Review &amp; Merge&quot;">​</a></h1><p><strong>Version:</strong> 1.0 · <strong>Owner:</strong> Developer (reviewer) · <strong>Gate:</strong> G2</p><h2 id="purpose-scope" tabindex="-1">Purpose &amp; scope <a class="header-anchor" href="#purpose-scope" aria-label="Permalink to &quot;Purpose &amp; scope&quot;">​</a></h2><p>Merge code only when automated guardrails pass and a qualified human approves. AI review is advisory unless configured as blocking for specific rules.</p><h2 id="roles" tabindex="-1">Roles <a class="header-anchor" href="#roles" aria-label="Permalink to &quot;Roles&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Role</th><th>RACI</th></tr></thead><tbody><tr><td>DEV (author)</td><td>R</td></tr><tr><td>DEV (reviewer)</td><td><strong>A</strong> — merge decision</td></tr><tr><td>ARCH</td><td>C — when ADR/spec touched</td></tr><tr><td>CI system</td><td><strong>A</strong> — objective gates</td></tr></tbody></table><h2 id="prerequisites" tabindex="-1">Prerequisites <a class="header-anchor" href="#prerequisites" aria-label="Permalink to &quot;Prerequisites&quot;">​</a></h2><ul><li>PR from SOP-004 with template complete</li><li>CI pipeline configured per tier (<a href="./../qa-guardrails.html">qa-guardrails.md</a>)</li><li>Linters, formatters, and static analyzers defined per <a href="./../guides/static-analysis-linting.html">Linters &amp; static analysis</a></li></ul><h2 id="procedure" tabindex="-1">Procedure <a class="header-anchor" href="#procedure" aria-label="Permalink to &quot;Procedure&quot;">​</a></h2><h3 id="author" tabindex="-1">Author <a class="header-anchor" href="#author" aria-label="Permalink to &quot;Author&quot;">​</a></h3><ol><li>Push branch; ensure all CI checks triggered.</li><li>Request reviewer (not self for T1/T2).</li><li>Address AI review comments: fix or document dismiss reason in PR thread.</li></ol><h3 id="reviewer" tabindex="-1">Reviewer <a class="header-anchor" href="#reviewer" aria-label="Permalink to &quot;Reviewer&quot;">​</a></h3><ol start="4"><li><strong>Verify traceability</strong> — Spec link, ADR IDs, ticket ID present.</li><li><strong>AI review</strong> — Read Bugbot/CodeGuru summary; validate high-severity findings.</li><li><strong>Human spot-check</strong> — Focus: error handling, auth, idempotency, test quality (not manual test execution).</li><li><strong>Contract alignment</strong> — Spot-check that tests reference OpenAPI operation IDs.</li><li><strong>Approve</strong> — Only when all required CI checks green (see checklist below).</li></ol><h3 id="merge" tabindex="-1">Merge <a class="header-anchor" href="#merge" aria-label="Permalink to &quot;Merge&quot;">​</a></h3><ol start="9"><li>Squash or merge per team convention; delete branch.</li><li>Release pipeline triggered → <a href="./SOP-006-release-deploy.html">SOP-006</a>.</li></ol><h2 id="required-ci-checks-minimum" tabindex="-1">Required CI checks (minimum) <a class="header-anchor" href="#required-ci-checks-minimum" aria-label="Permalink to &quot;Required CI checks (minimum)&quot;">​</a></h2><p>See <a href="./../guides/static-analysis-linting.html">Linters &amp; static analysis</a> for tool options. Checklist:</p><table tabindex="0"><thead><tr><th>Check</th><th>T1</th><th>T2</th><th>T3</th></tr></thead><tbody><tr><td>Format + lint + types</td><td>✓</td><td>✓</td><td>✓</td></tr><tr><td>Unit tests</td><td>✓</td><td>✓</td><td>✓</td></tr><tr><td>Contract tests</td><td>✓</td><td>✓</td><td>✓</td></tr><tr><td>Integration</td><td>✓</td><td>✓</td><td>optional</td></tr><tr><td>E2E</td><td>✓</td><td>✓</td><td>optional</td></tr><tr><td>SAST + SCA</td><td>✓</td><td>✓</td><td>✓</td></tr><tr><td>Secret scan</td><td>✓</td><td>✓</td><td>✓</td></tr><tr><td>OPA policy</td><td>✓</td><td>✓</td><td>✓</td></tr><tr><td>AI diff review</td><td>✓</td><td>✓</td><td>advisory</td></tr><tr><td>1 human approval</td><td>✓</td><td>✓</td><td>✓</td></tr><tr><td>ARCH approval (ADR/spec change)</td><td>✓</td><td>if touched</td><td>if touched</td></tr></tbody></table><h2 id="definition-of-done" tabindex="-1">Definition of Done <a class="header-anchor" href="#definition-of-done" aria-label="Permalink to &quot;Definition of Done&quot;">​</a></h2><ul><li>[ ] All required checks green</li><li>[ ] ≥ 1 human approval</li><li>[ ] No unresolved Critical/High security findings</li><li>[ ] Merged to <code>main</code></li></ul><h2 id="sla-escalation" tabindex="-1">SLA &amp; escalation <a class="header-anchor" href="#sla-escalation" aria-label="Permalink to &quot;SLA &amp; escalation&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Milestone</th><th>SLA</th></tr></thead><tbody><tr><td>First review</td><td>≤ 1 business day</td></tr><tr><td>Author response to feedback</td><td>≤ 1 business day</td></tr></tbody></table><p>Escalation: review stale &gt; 2 days → EM assigns reviewer.</p><h2 id="related-sops" tabindex="-1">Related SOPs <a class="header-anchor" href="#related-sops" aria-label="Permalink to &quot;Related SOPs&quot;">​</a></h2><ul><li><a href="./SOP-004-implementation.html">SOP-004</a> · <a href="./SOP-006-release-deploy.html">SOP-006</a> · <a href="./../qa-guardrails.html">qa-guardrails.md</a> · <a href="./../guides/static-analysis-linting.html">static-analysis-linting.md</a></li></ul>',25)])])}const m=t(d,[["render",s]]);export{p as __pageData,m as default};
